\pagestyle{empty}
\begin{document}
\begin{center}
  \textbf{\large Verifica di Storia: Il Medioevo} \\
  \vspace{0.3cm}
  \small \textbf{Nome:} \underline{\hspace{6cm}} \quad \textbf{Classe e Data:} \underline{\hspace{4cm}} \\
  \vspace{0.3cm}
  \textit{\small Svolgere tutti gli esercizi mostrando i passaggi.}
\end{center}
\subsection*{Esercizio 1: Concetti Fondamentali del Medioevo}
\begin{enumerate}[a)]
    \item Definire il concetto di "Alto Medioevo" e "Basso Medioevo", indicando approssimativamente i periodi storici a cui si riferiscono. (4 pt)
    \item Elencare tre delle principali caratteristiche socio-economiche dell'Alto Medioevo. (3 pt)
    \item Quale evento segna convenzionalmente l'inizio del Medioevo? (3 pt)
\end{enumerate}

\subsection*{Esercizio 2: Il Ruolo della Chiesa}
Spiegare, con riferimento a specifici esempi, il ruolo politico, culturale e spirituale della Chiesa Cattolica durante il Medioevo. (10 pt)

\subsection*{Esercizio 3: Le Invasioni Barbariche e la Formazione dei Regni Romanobarbarici}
\begin{enumerate}[a)]
    \item Identificare almeno tre dei principali popoli germanici che invasero l'Impero Romano d'Occidente. (3 pt)
    \item Descrivere brevemente le caratteristiche di uno dei regni romano-barbarici più significativi (es. Franchi, Visigoti, Ostrogoti). (4 pt)
    \item Quali furono le principali conseguenze a lungo termine delle invasioni per la penisola italiana? (3 pt)
\end{enumerate}

\subsection*{Esercizio 4: Il Feudalesimo}
\begin{enumerate}[a)]
    \item Definire il concetto di "feudo" e "vassallaggio". (4 pt)
    \item Spiegare la struttura gerarchica tipica di un sistema feudale. (3 pt)
    \item Indicare una delle cause che portarono alla crisi del sistema feudale nel Basso Medioevo. (3 pt)
\end{enumerate}

\subsection*{Esercizio 5: La Rinascita dopo l'Anno Mille}
Individuare e descrivere tre tra i principali fattori che contribuirono alla ripresa economica e sociale dell'Europa tra l'XI e il XIII secolo. (10 pt)

\subsection*{Esercizio 6: Le Crociate}
\begin{enumerate}[a)]
    \item Quale fu la causa scatenante della Prima Crociata? (3 pt)
    \item Indicare due conseguenze, positive o negative, delle Crociate sull'Europa medievale. (4 pt)
    \item Verificare la veridicità della seguente affermazione: "Le Crociate ebbero principalmente uno scopo puramente religioso, senza alcun interesse economico o politico." $\square$ \textbf{V} $\quad\square$ \textbf{F} (3 pt)
\end{enumerate}
\end{document}

